	add("rs13266634", "SLC30A8", "rs13266634", "8", "disease_risk", "diabetes", "T", "moderate", "Zinc Transporter — Beta Cell Insulin Secretion", "Reduces zinc transport into beta cells, impairing insulin crystallization. Additive T2D risk with TCF7L2.", "Zinc picolinate 15-25mg/day. Oysters, pumpkin seeds, red meat rich dietary sources.", "high", "17293876")
	add("rs1801282", "PPARG", "Pro12Ala", "3", "nutrition", "insulin", "G", "protective", "Improved Insulin Sensitivity — PPARG Ala", "Ala allele improves PPARG ligand binding, enhancing fat cell differentiation and glucose uptake. Reduces T2D and BMI.", "Unsaturated fats (olive oil, avocado, nuts) may further amplify PPARG Ala benefits.", "high", "10508198")
	add("rs4402960", "IGF2BP2", "rs4402960", "3", "disease_risk", "diabetes", "T", "moderate", "IGF2BP2 T2D Risk Locus", "Insulin-related gene variant associated with moderate T2D risk increase in multiple GWAS studies.", "Annual fasting glucose + HbA1c. Low-glycemic diet and regular exercise.", "moderate", "17293876")
	add("rs5215", "KCNJ11", "E23K", "11", "disease_risk", "diabetes", "T", "moderate", "KATP Channel — Beta Cell Insulin Release", "KCNJ11 E23K variant affects ATP-sensitive potassium channel in beta cells, impairing glucose-stimulated insulin secretion.", "Low-glycemic diet to reduce beta cell demand. Magnesium (important KATP cofactor). Regular moderate exercise.", "high", "14597819")
	add("rs10012946", "CDKAL1", "rs10012946", "6", "disease_risk", "diabetes", "C", "moderate", "CDKAL1 — CDK5 Regulatory Subunit, T2D Risk", "CDKAL1 C allele associated with reduced insulin secretion. One of the first T2D loci discovered in GWAS era.", "Reduce simple carbohydrate load. High-fiber diet blunts postprandial glucose spikes.", "moderate", "17293876")
	add("rs9300039", "CDKN2A/2B", "rs9300039", "9", "disease_risk", "diabetes", "C", "moderate", "9p21 — T2D and Pancreatic Beta Cell Function", "Same 9p21 locus that affects cardiovascular risk also impairs beta cell proliferation and T2D risk.", "Combined cardiovascular + metabolic prevention: Mediterranean diet, aerobic exercise, weight management.", "moderate", "17463248")
	add("rs10811661", "CDKN2B", "rs10811661", "9", "disease_risk", "diabetes", "T", "moderate", "CDKN2B — Cell Cycle & Beta Cell Mass", "CDKN2B T/T associated with reduced beta cell regeneration capacity and T2D risk.", "Aerobic exercise promotes beta cell preservation. Caloric moderation and fasting periods support cell health.", "moderate", "17463248")
	add("rs1111875", "HHEX", "rs1111875", "10", "disease_risk", "diabetes", "C", "moderate", "HHEX — Pancreatic Islet Development", "HHEX C allele associated with reduced insulin secretion and T2D risk. Involved in pancreatic development.", "Annual HbA1c monitoring. Structured meal timing to reduce insulin secretion burden.", "moderate", "17293876")
	add("rs7756992", "CDKAL1", "rs7756992", "6", "disease_risk", "diabetes", "G", "moderate", "CDKAL1 Secondary T2D Locus", "Second independent CDKAL1 signal affecting insulin secretion and T2D risk.", "Same management as primary CDKAL1 variant.", "moderate", "17293876")
	add("rs4712523", "GCK", "rs4712523", "7", "disease_risk", "diabetes", "G", "moderate", "Glucokinase — Glucose Sensing", "GCK variant affects glucose sensing in beta cells, altering the threshold for insulin release.", "Consistent meal timing. Avoid large glucose spikes. Continuous glucose monitoring can reveal individual response.", "moderate", "20581827")
	add("rs2237892", "KCNQ1", "rs2237892", "11", "disease_risk", "diabetes", "T", "moderate", "KCNQ1 — Potassium Channel, T2D Risk", "KCNQ1 T allele associated with T2D risk, particularly in East Asian populations. Affects potassium channel function in beta cells.", "Standard T2D prevention: weight management, exercise, low-glycemic diet.", "moderate", "18372903")
	add("rs163184", "KCNQ1", "rs163184", "11", "disease_risk", "diabetes", "G", "moderate", "KCNQ1 Secondary T2D Signal", "Secondary KCNQ1 variant with independent T2D association.", "Same dietary and lifestyle management as primary KCNQ1 variant.", "moderate", "18372903")
	add("rs2943641", "IRS1", "rs2943641", "2", "disease_risk", "insulin_resistance", "C", "moderate", "Insulin Receptor Substrate 1 — Insulin Signaling", "IRS1 variant impairs intracellular insulin signaling, directly causing insulin resistance independent of obesity.", "Resistance training particularly effective for IRS1-related insulin resistance. High-protein, low-glycemic diet.", "moderate", "21490949")
	add("rs1800437", "GIP", "rs1800437", "17", "disease_risk", "diabetes", "C", "moderate", "Gastric Inhibitory Polypeptide — Incretin Response", "GIP receptor variant affects incretin hormone function, reducing insulin secretion in response to meals.", "Structured meal timing. Avoid large infrequent meals. Probiotic and prebiotic foods support gut incretin production.", "moderate", "18372903")
	add("rs35767", "IGF1", "rs35767", "12", "hormones", "insulin_like_growth", "A", "moderate", "IGF-1 Levels — Growth, Metabolism & Cancer Risk", "IGF-1 promoter variant associated with lower IGF-1 levels. Low IGF-1 linked to longevity but also reduced muscle mass and bone density.", "Resistance training, adequate protein (1.6-2g/kg) and sleep support healthy IGF-1. Balance longevity vs. anabolic goals.", "moderate", "17557324")
	add("rs3916", "GCG", "rs3916", "2", "disease_risk", "diabetes", "T", "moderate", "Glucagon — Counter-Regulatory Hormone", "Glucagon gene variant affects the balance between insulin and glucagon signaling. Impaired glucagon suppression raises T2D risk.", "Low-glycemic diet reduces reliance on glucagon counter-regulation. Protein at each meal stabilizes glucagon levels.", "moderate", "15328820")
	add("rs5030952", "GLP1R", "rs5030952", "6", "disease_risk", "diabetes", "G", "moderate", "GLP-1 Receptor — Incretin Sensitivity", "GLP1R G allele associated with reduced incretin effect and T2D risk. GLP-1 receptor agonist medications (semaglutide) may be particularly beneficial.", "Probiotic and prebiotic foods boost endogenous GLP-1. Regular meals. Discuss GLP-1 agonist therapy with physician if diabetic.", "moderate", "22539549")
	add("rs9939609", "FTO", "rs9939609", "16", "nutrition", "obesity", "A", "high", "FTO Obesity Risk — Appetite Dysregulation", "Homozygous A/A: ~1.67x obesity risk via elevated ghrelin and reduced satiety. Effect strongly modified by exercise.", "High-protein diet (1.6-2g/kg), high-fiber meals, structured meal timing. 5+ days/week aerobic exercise nearly eliminates FTO phenotype.", "high", "17434869")
	add("rs1558902", "FTO", "rs1558902", "16", "nutrition", "obesity", "A", "high", "FTO Secondary Obesity Locus", "Secondary FTO variant with additive effect on body weight and BMI.", "Same intervention as primary FTO: exercise + high-protein diet.", "high", "22344219")
	add("rs6499640", "FTO", "rs6499640", "16", "nutrition", "obesity", "T", "moderate", "FTO Tertiary BMI Association", "Third FTO region variant contributing to BMI and obesity risk.", "Combined FTO risk: exercise is the primary modifier. Structured eating environment critical.", "moderate", "20935630")
	add("rs4994", "ADRB3", "Trp64Arg", "8", "fitness", "fat_metabolism", "T", "moderate", "Beta-3 Adrenergic Receptor — Fat Mobilization", "Trp64Arg reduces fat mobilization during exercise. Associated with higher BMI and lower resting metabolic rate.", "Higher exercise volume needed for fat loss. Protein intake particularly important. Avoid prolonged caloric restriction.", "moderate", "10400985")
	add("rs1800544", "ADRA2A", "rs1800544", "10", "nutrition", "obesity", "C", "moderate", "Alpha-2A Adrenergic Receptor — Fat Mobilization", "ADRA2A variant affects sympathetic regulation of fat release from adipocytes. C allele associated with obesity risk.", "Aerobic exercise (most powerful fat mobilizer). Adequate sleep (supports catecholamine sensitivity).", "moderate", "17893252")
	add("rs2229616", "MC3R", "rs2229616", "20", "nutrition", "obesity", "A", "moderate", "Melanocortin-3 Receptor — Energy Expenditure", "MC3R variant affects hypothalamic regulation of energy balance. A allele associated with reduced energy expenditure and obesity.", "Consistent exercise schedule. Adequate sleep (critical for hypothalamic energy regulation). Protein-dominant diet.", "moderate", "18445306")
	add("rs52820871", "MC4R", "rs52820871", "18", "nutrition", "obesity", "T", "high", "Melanocortin-4 Receptor — Satiety Signaling", "MC4R T allele impairs satiety signaling in the hypothalamus, causing hyperphagia. Most common monogenic obesity gene.", "Structured eating schedule, high-protein diet, cognitive behavioral strategies for eating behavior. Exercise critical.", "high", "17463248")
	add("rs17300539", "ADIPOQ", "rs17300539", "3", "nutrition", "adipokines", "G", "protective", "Adiponectin — Anti-Inflammatory Adipokine", "ADIPOQ G allele associated with higher adiponectin levels, improving insulin sensitivity and reducing inflammation.", "Favorable variant. Aerobic exercise raises adiponectin. Maintain healthy BMI to preserve adiponectin advantage.", "moderate", "14579357")
	add("rs2241766", "ADIPOQ", "rs2241766", "3", "disease_risk", "metabolic_syndrome", "G", "moderate", "Adiponectin — Metabolic Syndrome Risk", "ADIPOQ G allele in this position associated with lower adiponectin and higher metabolic syndrome risk.", "Weight management + exercise raises adiponectin. Omega-3 supplementation supports adiponectin signaling.", "moderate", "14579357")
	add("rs7799039", "LEP", "rs7799039", "7", "nutrition", "leptin", "A", "moderate", "Leptin Promoter — Leptin Regulation", "LEP promoter variant affects leptin expression. A allele associated with lower leptin (reduced satiety) and obesity risk.", "High-protein diet most powerful for raising satiety independent of leptin. Sleep quality critical for leptin rhythm.", "moderate", "11313517")
	add("rs1137101", "LEPR", "Gln223Arg", "1", "nutrition", "leptin_resistance", "G", "moderate", "Leptin Receptor — Leptin Resistance", "LEPR Arg223 (G) associated with reduced leptin receptor sensitivity, causing leptin resistance.", "Aerobic exercise restores leptin sensitivity. Avoid chronic caloric restriction (raises leptin resistance). Adequate sleep.", "moderate", "10486054")
	add("rs1421085", "FTO", "rs1421085", "16", "nutrition", "obesity", "C", "high", "FTO Functional Variant — IRX3/IRX5 Expression", "Most recently identified functional FTO variant. Disrupts ARID5B binding, raising IRX3 and IRX5 expression, shifting adipocytes from thermogenic beige to white fat storage.", "Regular cold exposure (mild: cool showers, cold environments) promotes beige adipogenesis — directly counteracts this variant. Exercise + high-protein diet.", "high", "29988969")
	add("rs4244285", "CYP2C19", "*2", "10", "pharmacogenomics", "antiplatelet", "A", "high", "CYP2C19 *2 — Clopidogrel Poor Metabolizer", "*2 impairs clopidogrel activation. Poor metabolizers get inadequate antiplatelet effect, increasing stent thrombosis risk. Also affects omeprazole, escitalopram, several antidepressants.", "CRITICAL: Inform cardiologist before clopidogrel. Prasugrel or ticagrelor may be indicated. CYP2C19 genotyping is FDA-recommended.", "high", "19706858")
	add("rs4986893", "CYP2C19", "*3", "10", "pharmacogenomics", "antiplatelet", "A", "high", "CYP2C19 *3 — Additional Poor Metabolizer Allele", "*3 allele causes further CYP2C19 loss of function. Combined with *2, severely impairs drug metabolism.", "Same protocol as CYP2C19 *2. Disclose to cardiologist, psychiatrist, and gastroenterologist.", "high", "19706858")
	add("rs12248560", "CYP2C19", "*17", "10", "pharmacogenomics", "antidepressants", "T", "moderate", "CYP2C19 *17 — Ultrarapid Metabolizer", "*17 increases CYP2C19 activity. Drugs metabolized too quickly — standard doses may be subtherapeutic. Clopidogrel may be more effective.", "Inform physician. Standard SSRI doses may be insufficient. Proton pump inhibitors may require higher doses.", "moderate", "19706858")
	add("rs1799853", "CYP2C9", "*2", "10", "pharmacogenomics", "anticoagulants", "T", "high", "CYP2C9 *2 — Reduced Warfarin Metabolism", "*2 reduces warfarin metabolism 10-20%. Standard doses cause dangerous over-anticoagulation and bleeding.", "CRITICAL: Disclose to all physicians. FDA recommends genotype-guided warfarin dosing. Also affects NSAIDs, phenytoin.", "high", "9457302")
	add("rs1057910", "CYP2C9", "*3", "10", "pharmacogenomics", "anticoagulants", "C", "high", "CYP2C9 *3 — Severe Warfarin Sensitivity", "*3 reduces warfarin metabolism ~90%. Very high bleeding risk at standard doses. Requires dramatic dose reduction.", "CRITICAL: Warfarin dose must be substantially reduced. Very close INR monitoring essential. Disclose to all physicians.", "high", "9457302")
	add("rs9923231", "VKORC1", "rs9923231", "16", "pharmacogenomics", "anticoagulants", "T", "high", "VKORC1 — Warfarin Dose Requirement", "VKORC1 T allele reduces vitamin K epoxide reductase activity. Major determinant of warfarin dose alongside CYP2C9.", "CRITICAL: T allele carriers need significantly lower warfarin doses. FDA recommends VKORC1 genotyping before warfarin.", "high", "15700771")
	add("rs3892097", "CYP2D6", "*4", "22", "pharmacogenomics", "opioids", "A", "high", "CYP2D6 *4 — Codeine Poor Metabolizer", "*4 prevents codeine activation to morphine. No pain relief + potential toxicity. Tamoxifen activation impaired. Many antidepressants require dose adjustment.", "CRITICAL: Codeine and tramadol contraindicated. Tamoxifen may be ineffective for ER+ breast cancer. Disclose to all physicians.", "high", "12386134")
	add("rs1065852", "CYP2D6", "*10", "22", "pharmacogenomics", "antidepressants", "C", "moderate", "CYP2D6 *10 — Intermediate Metabolizer", "*10 allele reduces CYP2D6 activity ~50%. Standard doses of many antidepressants, antipsychotics, and beta-blockers may be elevated.", "Inform psychiatrist and cardiologist. May need dose adjustment for amitriptyline, haloperidol, metoprolol, risperidone.", "moderate", "12386134")
	add("rs16947", "CYP2D6", "*2", "22", "pharmacogenomics", "antidepressants", "G", "moderate", "CYP2D6 *2 — CYP2D6 Normal/Increased Activity", "*2 allele. When duplicated (*2xN), creates ultrarapid metabolizer with subtherapeutic drug levels at standard doses.", "If CYP2D6 gene duplicated: standard antidepressant and opioid doses may be insufficient. Discuss with psychiatrist.", "moderate", "12386134")
	add("rs1045642", "ABCB1", "C3435T", "7", "pharmacogenomics", "drug_transport", "T", "moderate", "P-Glycoprotein — Multi-Drug Absorption", "ABCB1 variant affects intestinal absorption and blood-brain barrier crossing for digoxin, statins, HIV drugs, antidepressants.", "Inform physician when prescribed digoxin, cyclosporine, tacrolimus, some statins, HIV medications. Dose adjustment may be needed.", "moderate", "11919558")
	add("rs1800460", "TPMT", "rs1800460", "6", "pharmacogenomics", "immunosuppressants", "A", "high", "TPMT — Thiopurine Toxicity Risk", "TPMT variant reduces thiopurine metabolism. Standard azathioprine/6-MP doses cause severe bone marrow suppression.", "CRITICAL: Disclose if prescribed azathioprine, 6-mercaptopurine, or thioguanine. Significant dose reduction required. FDA mandates genotyping.", "high", "9536169")
	add("rs1800462", "TPMT", "rs1800462", "6", "pharmacogenomics", "immunosuppressants", "G", "high", "TPMT *2 — Thiopurine Severe Toxicity", "TPMT *2 allele, combined with *3, causes near-complete enzyme deficiency. Life-threatening thiopurine toxicity at standard doses.", "CRITICAL: Thiopurines contraindicated or require dramatically reduced doses with very close monitoring.", "high", "9536169")
	add("rs9923231", "VKORC1", "rs9923231", "16", "pharmacogenomics", "anticoagulants", "T", "high", "VKORC1 — Vitamin K Antagonist Sensitivity", "Combined with CYP2C9 *2/*3, determines warfarin dose requirement. T allele: lower dose needed.", "See primary VKORC1 entry. Combined CYP2C9 + VKORC1 genotyping predicts warfarin dose with >50% accuracy.", "high", "15700771")
	add("rs4149056", "SLCO1B1", "*5", "12", "pharmacogenomics", "statins", "C", "high", "SLCO1B1 *5 — Statin Myopathy Risk", "*5 impairs hepatic statin uptake, raising plasma statin levels and causing muscle damage (myopathy, rhabdomyolysis).", "CRITICAL: Report any muscle pain on statins immediately. Prefer pravastatin or fluvastatin (less SLCO1B1-dependent). Lower doses safer.", "high", "18650507")
	add("rs2306283", "SLCO1B1", "N130D", "12", "pharmacogenomics", "statins", "G", "moderate", "SLCO1B1 N130D — Statin Transport Modifier", "Secondary SLCO1B1 variant affecting statin hepatic uptake and plasma levels.", "Monitor for statin myopathy. Report muscle pain, weakness, or dark urine to physician immediately.", "moderate", "18650507")
	add("rs2032582", "ABCB1", "G2677T", "7", "pharmacogenomics", "drug_transport", "T", "moderate", "P-Glycoprotein G2677T — Drug Bioavailability", "ABCB1 triallelic SNP. T allele affects P-gp efflux of many drugs including tacrolimus, digoxin, and several chemotherapy agents.", "Disclose when prescribed organ transplant medications, cardiac glycosides, or certain chemotherapy agents.", "moderate", "12386134")
	add("rs1128503", "ABCB1", "C1236T", "7", "pharmacogenomics", "drug_transport", "T", "moderate", "P-Glycoprotein C1236T — Haplotype Effect", "In combination with rs2032582 and rs1045642 forms the most common ABCB1 haplotype affecting drug transport.", "Same considerations as other ABCB1 variants. Haplotype analysis provides more complete picture.", "moderate", "12386134")
	add("rs4149056", "SLCO1B1", "rs4149056", "12", "pharmacogenomics", "methotrexate", "C", "moderate", "SLCO1B1 — Methotrexate Toxicity", "SLCO1B1 C allele also affects methotrexate hepatic uptake, relevant in rheumatoid arthritis and cancer treatment.", "Disclose to rheumatologist and oncologist. Closer liver function monitoring during methotrexate therapy.", "moderate", "18650507")
	add("rs1800497", "DRD2", "Taq1A", "11", "pharmacogenomics", "antipsychotics", "A", "moderate", "DRD2 Taq1A — Antipsychotic Response", "DRD2 A1 allele reduces D2 receptor density. May affect antipsychotic drug efficacy and side effects (particularly tardive dyskinesia).", "Disclose to psychiatrist. A1 allele may require different antipsychotic choice or dose. Monitor for movement disorders.", "moderate", "7634523")
	add("rs6277", "DRD2", "rs6277", "11", "pharmacogenomics", "antipsychotics", "T", "moderate", "DRD2 Expression — Antipsychotic & Dopamine Response", "DRD2 rs6277 T allele affects mRNA stability and D2 receptor expression. Influences response to antipsychotics and dopaminergic drugs.", "Inform psychiatrist when prescribed antipsychotics, methylphenidate, or dopamine agonists.", "moderate", "11689678")
	add("rs6313", "HTR2A", "rs6313", "13", "pharmacogenomics", "antidepressants", "T", "moderate", "Serotonin 2A Receptor — Antidepressant Response", "HTR2A T allele influences serotonin 2A receptor expression and antidepressant response, particularly to SSRIs and atypical antipsychotics.", "Disclose to psychiatrist. T allele may predict differential SSRI response or need for higher doses.", "moderate", "12560764")
	add("rs2187668", "HLA-DQA1", "rs2187668", "6", "pharmacogenomics", "abacavir", "A", "high", "HLA-DQA1 — Abacavir Hypersensitivity Proxy", "HLA-DQA1 variant in strong LD with HLA-B*57:01. Positive test predicts abacavir hypersensitivity reaction in HIV treatment.", "CRITICAL: FDA mandates HLA-B*57:01 screening before abacavir. If positive, abacavir is contraindicated.", "high", "22419872")
	add("rs2395029", "HLA-B", "B*57:01 proxy", "6", "pharmacogenomics", "abacavir", "G", "high", "HLA-B*57:01 — Abacavir Severe Hypersensitivity", "HLA-B*57:01 causes severe, potentially life-threatening hypersensitivity to abacavir in HIV therapy.", "CRITICAL: Abacavir absolutely contraindicated if HLA-B*57:01 positive. Alternative HIV regimen required.", "high", "22419872")
	add("rs4986774", "DPYD", "D949V", "1", "pharmacogenomics", "fluorouracil", "T", "high", "DPYD — Fluorouracil Severe Toxicity Risk", "DPYD variant reduces dihydropyrimidine dehydrogenase, impairing 5-FU metabolism. Life-threatening toxicity at standard doses.", "CRITICAL: DPYD genotyping recommended before 5-FU, capecitabine chemotherapy. Dose reduction or alternative required.", "high", "15459013")
	add("rs3918290", "DPYD", "*2A", "1", "pharmacogenomics", "fluorouracil", "A", "high", "DPYD *2A — Complete DPD Deficiency Risk", "Most significant DPYD variant. Causes near-complete DPD enzyme deficiency. 5-FU is potentially lethal at standard doses.", "CRITICAL: 5-FU and capecitabine contraindicated without DPYD genotyping. Inform oncologist before chemotherapy.", "high", "15459013")
	add("rs1695", "GSTP1", "I105V", "11", "pharmacogenomics", "chemotherapy", "G", "moderate", "Glutathione S-Transferase P1 — Chemotherapy Detoxification", "GSTP1 Val105 reduces detoxification of platinum-based chemotherapy, affecting both efficacy and toxicity.", "Inform oncologist. Val105 may predict different responses to cisplatin/oxaliplatin and benefit from antioxidant support.", "moderate", "10468581")
	add("rs4633", "COMT", "rs4633", "22", "pharmacogenomics", "opioids", "C", "moderate", "COMT — Opioid Requirement & Pain Perception", "COMT variant affects dopamine-mediated pain modulation. Met158 (C) carriers often require lower opioid doses for pain relief.", "Inform pain physician. Reduced opioid requirement may allow lower doses. Non-opioid pain management particularly important.", "moderate", "14966513")
	add("rs2032582", "ABCB1", "rs2032582", "7", "pharmacogenomics", "immunosuppressants", "T", "moderate", "P-Glycoprotein — Tacrolimus Bioavailability", "ABCB1 T allele affects tacrolimus gut absorption and blood-brain barrier transport. Important in organ transplant patients.", "Inform transplant physician. Tacrolimus dose may need adjustment based on ABCB1 genotype.", "moderate", "14997427")
	add("rs4148323", "UGT1A1", "*28", "2", "pharmacogenomics", "irinotecan", "A", "high", "UGT1A1 *28 — Irinotecan Toxicity", "UGT1A1 *28 reduces glucuronidation of SN-38 (active irinotecan metabolite), causing severe diarrhea and bone marrow suppression.", "CRITICAL: FDA recommends UGT1A1 *28 genotyping before irinotecan chemotherapy. *28/*28: 50% dose reduction typically required.", "high", "15273544")
	add("rs4149056", "SLCO1B1", "rs4149056", "12", "pharmacogenomics", "repaglinide", "C", "moderate", "SLCO1B1 — Repaglinide (Diabetes Drug) Exposure", "SLCO1B1 C allele increases plasma repaglinide concentrations, elevating hypoglycemia risk.", "Inform diabetologist if prescribed repaglinide or nateglinide. Lower starting dose and closer blood glucose monitoring.", "moderate", "18650507")
	add("rs7900194", "CYP2C8", "*3", "1", "pharmacogenomics", "diabetes_drugs", "A", "moderate", "CYP2C8 — Thiazolidinedione & Amodiaquine Metabolism", "CYP2C8 *3 variant reduces metabolism of rosiglitazone, pioglitazone, and antimalarial drugs.", "Inform physician when prescribed rosiglitazone, pioglitazone (diabetes), or amodiaquine (malaria). Dose adjustment may be needed.", "moderate", "16908744")
	add("rs2279343", "CYP2B6", "*6", "19", "pharmacogenomics", "hiv_drugs", "T", "high", "CYP2B6 *6 — Efavirenz (HIV) Metabolism", "CYP2B6 *6 reduces efavirenz metabolism. *6/*6: very high plasma efavirenz levels causing neuropsychiatric toxicity.", "CRITICAL: Disclose to HIV physician. Efavirenz dosing must be adjusted. Alternative: rilpivirine or dolutegravir regimens.", "high", "16048142")
	add("rs8192678", "PPARGC1A", "Gly482Ser", "4", "pharmacogenomics", "metformin", "A", "moderate", "PPARGC1A — Metformin Response", "PPARGC1A Ser482 variant affects mitochondrial biogenesis response. May influence metformin metabolic benefits.", "Aerobic exercise maximizes PPARGC1A-metformin synergy. Discuss with physician if on metformin.", "moderate", "15654041")
	add("rs316019", "SLC22A2", "rs316019", "6", "pharmacogenomics", "metformin", "A", "moderate", "OCT2 — Metformin Renal Transport", "SLC22A2 OCT2 variant affects metformin renal secretion. A allele reduces OCT2, lowering metformin clearance and increasing plasma levels.", "Inform prescribing physician. Lower metformin starting dose may be appropriate. Monitor renal function closely.", "moderate", "17468180")
	add("rs1051266", "SLC19A1", "H27R", "21", "pharmacogenomics", "methotrexate", "G", "moderate", "SLC19A1 — Methotrexate Cellular Uptake", "SLC19A1 is the primary methotrexate transporter. G allele reduces cellular uptake, potentially reducing efficacy in cancer/autoimmune treatment.", "Inform rheumatologist or oncologist. Higher methotrexate doses or leucovorin rescue may be needed.", "moderate", "16372347")
	add("rs3745274", "CYP2B6", "*9", "19", "pharmacogenomics", "hiv_drugs", "T", "moderate", "CYP2B6 *9 — Efavirenz Secondary Variant", "Secondary CYP2B6 variant modifying efavirenz and bupropion metabolism.", "Inform HIV physician and psychiatrist if prescribed efavirenz or bupropion.", "moderate", "16048142")
	add("rs1042522", "TP53", "Arg72Pro", "17", "pharmacogenomics", "chemotherapy", "G", "moderate", "TP53 — Chemotherapy Response & Apoptosis", "TP53 Pro72 variant affects apoptotic response to DNA-damaging chemotherapy. Pro72 may have reduced apoptotic efficiency.", "Inform oncologist. Pro72/Pro72 may require different chemotherapy selection or doses.", "moderate", "9560124")
	add("rs1800566", "NQO1", "P187S", "16", "pharmacogenomics", "chemotherapy", "T", "moderate", "NQO1 — Quinone Chemotherapy Metabolism", "NQO1 P187S reduces quinone oxidoreductase activity, affecting metabolism of mitomycin C and certain chemotherapy agents. Also increases sensitivity to benzene toxicity.", "Inform oncologist. Avoid heavy benzene exposure (cigarette smoke, industrial chemicals). Report unusual chemotherapy toxicities.", "moderate", "15361592")
